var weightVal = weight * 1.0;
var beesNumberVal = beesNumber * 1.0;
var emptyHiveWeightVal = emptyHiveWeight * 1.0;

// peso medio ape
var beeWeightKg = 0.0001;

// miele per ape
var honeyPerBee = 0.0008;

// capacità arnia
var hiveCapacity = 35;

// peso api
var beesWeight = beesNumberVal * beeWeightKg;

// peso minimo
var minWeight = emptyHiveWeightVal + beesWeight;

// miele
var honeyWeight = weightVal - minWeight;

if (honeyWeight < 0) {
    honeyWeight = 0;
}

// miele teorico
var maxHoneyFromBees = beesNumberVal * honeyPerBee;

// massimo miele
var maxHoneyWeight = maxHoneyFromBees;

if (hiveCapacity < maxHoneyWeight) {
    maxHoneyWeight = hiveCapacity;
}

// percentuale
var honeyPercentage = 0;

if (maxHoneyWeight > 0) {
    honeyPercentage = (honeyWeight / maxHoneyWeight) * 100;
}

if (honeyPercentage > 100) {
    honeyPercentage = 100;
}

return {
    honeyPct: honeyPercentage,
    honeyWeightKg: honeyWeight,
    minWeightKg: minWeight
};
